class Solution {
    public String breakPalindrome(String palindrome) {
        char[] chars = palindrome.toCharArray();
        int n = palindrome.length();

        // If the length of the palindrome is 1, there's no way to make it not a palindrome by replacing one character
        if (n == 1) {
            return "";
        }

        // Try to replace the first non-'a' character with 'a'
        for (int i = 0; i < n / 2; i++) {
            if (chars[i] != 'a') {
                chars[i] = 'a';
                return new String(chars);
            }
        }

        // If all characters are 'a', replace the last character with 'b'
        chars[n - 1] = 'b';
        return new String(chars);
    }
}
```
